{
  "competency_groups": [
    {
      "code": "C1",
      "title": "Conceptual Foundations and Measurement",
      "description": "Equip learners with tools to understand the working of Chemistry, develop conceptual foundations, enable representation at macroscopic/molecular/symbolic levels, identify patterns, and inculcate problem-solving skills.",
      "competencies": [
        "Understand nature of matter, properties, measurement, uncertainty, laws of combination, atomic theory",
        "Apply mole concept, molar masses, percentage composition, stoichiometry calculations",
        "Represent chemical phenomena at macroscopic, molecular, and symbolic levels"
      ],
      "unit_name": "Some Basic Concepts of Chemistry",
      "chapter_name": "Some Basic Concepts of Chemistry"
    },
    {
      "code": "C2",
      "title": "Atomic Structure and Quantum Mechanics",
      "description": "Enable learners to identify patterns underlying chemical phenomena through understanding atomic models, quantum mechanics, and electronic configurations.",
      "competencies": [
        "Trace discovery of sub-atomic particles and evolution from Bohr's model to Quantum Mechanical Model"
      ],
      "unit_name": "Structure of Atom",
      "chapter_name": "Structure of Atom"
    },
    {
      "code": "C3",
      "title": "Periodic Classification and Trends",
      "description": "Enable learners to identify patterns in element properties through classification, periodic law, electronic configuration, and trends across blocks.",
      "competencies": [
        "Apply modern periodic law and understand genesis of periodic classification"
      ],
      "unit_name": "Classification of Elements and Periodicity in Properties",
      "chapter_name": "Classification of Elements and Periodicity in Properties"
    },
    {
      "code": "C4",
      "title": "Chemical Bonding Theories",
      "description": "Enable learners to represent chemical phenomena at molecular levels using various bonding theories.",
      "competencies": [
        "Apply Kossel-Lewis approach, VSEPR theory, Valence Bond Theory, Hybridisation, and Molecular Orbital Theory"
      ],
      "unit_name": "Chemical Bonding and Molecular Structure",
      "chapter_name": "Chemical Bonding and Molecular Structure"
    },
    {
      "code": "C5",
      "title": "Thermodynamics and Spontaneity",
      "description": "Enable learners to apply thermodynamic principles including enthalpy, entropy, Gibbs energy, and spontaneity.",
      "competencies": [
        "Apply concepts of calorimetry, reaction enthalpies, spontaneity, and equilibrium via Gibbs Energy"
      ],
      "unit_name": "Thermodynamics",
      "chapter_name": "Thermodynamics"
    },
    {
      "code": "C6",
      "title": "Chemical Equilibrium Principles",
      "description": "Enable learners to identify patterns in equilibrium states and factors affecting them.",
      "competencies": [
        "Apply Law of Chemical Equilibrium, understand homogeneous/heterogeneous equilibria, relationship between K, Q, G"
      ],
      "unit_name": "Equilibrium",
      "chapter_name": "Equilibrium"
    },
    {
      "code": "C7",
      "title": "Redox and Electrode Processes",
      "description": "Enable learners to represent redox phenomena in terms of electron transfer.",
      "competencies": [
        "Apply classical ideas, oxidation numbers, and electrode processes"
      ],
      "unit_name": "Redox Reactions",
      "chapter_name": "Redox Reactions"
    },
    {
      "code": "C8",
      "title": "Organic Chemistry Fundamentals",
      "description": "Enable learners to represent organic compounds structurally and understand reaction mechanisms.",
      "competencies": [
        "Apply structural representations, nomenclature, isomerism concepts, and fundamental reaction mechanism principles"
      ],
      "unit_name": "Organic Chemistry: Some basic Principles and Techniques",
      "chapter_name": "Organic Chemistry: Some basic Principles and Techniques"
    },
    {
      "code": "C9",
      "title": "Hydrocarbon Classification and Properties",
      "description": "Enable learners to classify hydrocarbons and understand their properties.",
      "competencies": [
        "Classify alkanes, alkenes, alkynes, aromatic hydrocarbons"
      ],
      "unit_name": "Hydrocarbons",
      "chapter_name": "Hydrocarbons"
    },
    {
      "code": "C10",
      "title": "Solutions and Colligative Properties",
      "description": "Enable learners to apply concepts of solution concentration, solubility, and colligative properties.",
      "competencies": [
        "Apply expressions for concentration, ideal/non-ideal solutions, vapor pressure, and determination of molar mass"
      ],
      "unit_name": "Solutions",
      "chapter_name": "Solutions"
    },
    {
      "code": "C11",
      "title": "Electrochemistry Applications",
      "description": "Enable learners to apply electrochemical principles including cells, Nernst equation, and corrosion.",
      "competencies": [
        "Apply concepts of galvanic/electrolytic cells, batteries, fuel cells, and corrosion"
      ],
      "unit_name": "Electrochemistry",
      "chapter_name": "Electrochemistry"
    },
    {
      "code": "C12",
      "title": "Chemical Kinetics Analysis",
      "description": "Enable learners to analyze reaction rates and factors influencing them.",
      "competencies": [
        "Apply integrated rate equations, temperature dependence, collision theory"
      ],
      "unit_name": "Chemical Kinetics",
      "chapter_name": "Chemical Kinetics"
    },
    {
      "code": "C13",
      "title": "d- and f-Block Elements Properties",
      "description": "Enable learners to identify patterns in transition elements, lanthanoids, and actinoids.",
      "competencies": [
        "Apply electronic configurations, general properties of d-block, applications"
      ],
      "unit_name": "d-and f -Block Elements",
      "chapter_name": "d- and f- Block Elements"
    },
    {
      "code": "C14",
      "title": "Coordination Compounds Bonding",
      "description": "Enable learners to represent coordination compounds using Werner's theory, bonding models, and isomerism.",
      "competencies": [
        "Apply nomenclature, isomerism concepts, metal carbonyl bonding"
      ],
      "unit_name": "Coordination Compounds",
      "chapter_name": "Coordination Compounds"
    },
    {
      "code": "C15",
      "title": "Organic Functional Groups and Synthesis",
      "description": "Enable learners to represent organic compounds with functional groups, understand nomenclature, preparation methods, and reactions.",
      "competencies": [
        "Apply classification, nomenclature, structures of haloalkanes/haloarenes, alcohols/phenols/ethers"
      ],
      "unit_name": "Haloalkanes and Haloarenes",
      "chapter_name": "Haloalkanes and Haloarenes"
    },
    {
      "code": "C16",
      "title": "Carbonyl Chemistry and Amines",
      "description": "Enable learners to represent carbonyl groups, carboxyl groups, and amines structurally.",
      "competencies": [
        "Apply nomenclature of aldehydes/ketones/carboxylic acids/amines"
      ],
      "unit_name": "Alcohols, Phenols and Ethers",
      "chapter_name": "Alcohols, Phenols and Ethers"
    },
    {
      "code": "C17",
      "title": "Biomolecules Structure and Function",
      "description": "Enable learners to represent biomolecules including carbohydrates, proteins, vitamins, nucleic acids.",
      "competencies": [
        "Represent structures of carbohydrates, proteins, enzymes, vitamins, hormones"
      ],
      "unit_name": "Biomolecules",
      "chapter_name": "Biomolecules"
    },
    {
      "code": "C18",
      "title": "Surface Chemistry and Colloids",
      "description": "Enable learners to identify patterns in colloidal states, adsorption, emulsions.",
      "competencies": [
        "Apply concepts of physisorption/chemisorption, lyophilic/lyophobic properties"
      ],
      "unit_name": "Surface Chemistry",
      "chapter_name": "Surface Chemistry"
    },
    {
      "code": "C19",
      "title": "Isolation and Industrial Processes",
      "description": "Enable learners to apply principles of extraction, concentration, oxidation, reduction.",
      "competencies": [
        "Apply methods of isolation including electrolytic refining"
      ],
      "unit_name": "General Principles and Processes of Isolation of Elements",
      "chapter_name": "General Principles and Processes of Isolation of Elements"
    },
    {
      "code": "C20",
      "title": "Polymers Chemistry",
      "description": "Enable learners to represent polymer structures including homopolymers and copolymers.",
      "competencies": [
        "Apply concepts of polymerisation"
      ],
      "unit_name": "Polymers",
      "chapter_name": "Polymers"
    },
    {
      "code": "C21",
      "title": "Chemistry in Everyday Life and Environment",
      "description": "Enable learners to contribute to frontier research areas related to climate change, environmental issues.",
      "competencies": [
        "Apply knowledge of chemicals in medicines (analgesics, antibiotics), food preservatives"
      ],
      "unit_name": "Chemistry in Everyday life",
      "chapter_name": "Chemistry in Everyday life"
    }
  ]
}
